VALUES
  ('police-f3743df6-moex-00290', 'police-f3743df6', 'police-f3743df6-moex-111-15a7b19c', 'sub-police-f3743df6-01', NULL, 'single_choice', '依憲法及司法院大法官解釋，關於立法院質詢權，下列敘述何者錯誤？', '["只有行政院院長及行政院各部會首長有至立法院院會接受質詢之義務", "立法院各委員會得邀請民間團體代表到會備詢", "司法院院長得列席立法院院會陳述意見", "參謀總長並無至立法院各委員會備詢之義務"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:19+00:00", "source_pdf_sha1": "a526a29fb5cc", "answer_pdf_sha1": "53cf396c4907", "source_family": "moex-gov-tw", "moex": {"exam_code": "111070", "c": "513", "s": "0205", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中華民國憲法與警察專業英文", "year": "111", "exam_name": "111年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "警察法制人員"}'::jsonb, NULL),
  ('police-f3743df6-moex-00291', 'police-f3743df6', 'police-f3743df6-moex-111-15a7b19c', 'sub-police-f3743df6-01', NULL, 'single_choice', '依司法院釋字第627號解釋，下列有關總統國家機密特權之敘述，何者錯誤？', '["於法院訴訟程序進行中，總統尚非不得將系爭資訊依法改核定為國家機密", "法院審理個案，如涉及總統已提出之資訊者，即無國家機密保護法之適用", "依國家機密特權，總統就國家機密事項於刑事訴訟程序應享有拒絕證言權", "總統就有關國家安全、國防以及外交之國家機密事項，有決定不予公開之權力"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:19+00:00", "source_pdf_sha1": "a526a29fb5cc", "answer_pdf_sha1": "53cf396c4907", "source_family": "moex-gov-tw", "moex": {"exam_code": "111070", "c": "513", "s": "0205", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中華民國憲法與警察專業英文", "year": "111", "exam_name": "111年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "警察法制人員"}'::jsonb, NULL),
  ('police-f3743df6-moex-00292', 'police-f3743df6', 'police-f3743df6-moex-111-15a7b19c', 'sub-police-f3743df6-01', NULL, 'single_choice', '依憲法對於社會安全之規定，下列敘述何者錯誤？', '["犯罪被害人所受損害，應由國家予以賠償", "人民具有工作能力者，國家應予以適當之工作機會", "兒童從事勞動者，應予以特別之保護", "國家應制定保護農民之法律"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:19+00:00", "source_pdf_sha1": "a526a29fb5cc", "answer_pdf_sha1": "53cf396c4907", "source_family": "moex-gov-tw", "moex": {"exam_code": "111070", "c": "513", "s": "0205", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中華民國憲法與警察專業英文", "year": "111", "exam_name": "111年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "警察法制人員"}'::jsonb, NULL),
  ('police-f3743df6-moex-00293', 'police-f3743df6', 'police-f3743df6-moex-111-15a7b19c', 'sub-police-f3743df6-01', NULL, 'single_choice', '依司法院大法官解釋，關於行政一體原則，下列敘述何者錯誤？', '["行政院為國家最高行政機關，須為其所屬機關之整體施政表現負責", "除憲法別有規定外，無論各行政專業單位如何分工，所有國家之行政事務最終均歸由行政 院指揮監督", "立法院得立法設置獨立機關，自主運作，完全排除行政院之監督", "立法院得以法律限制行政院對獨立機關之人事決定權，但有其界限"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:19+00:00", "source_pdf_sha1": "a526a29fb5cc", "answer_pdf_sha1": "53cf396c4907", "source_family": "moex-gov-tw", "moex": {"exam_code": "111070", "c": "513", "s": "0205", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中華民國憲法與警察專業英文", "year": "111", "exam_name": "111年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "警察法制人員"}'::jsonb, NULL),
  ('police-f3743df6-moex-00294', 'police-f3743df6', 'police-f3743df6-moex-111-15a7b19c', 'sub-police-f3743df6-01', NULL, 'single_choice', '依司法院大法官解釋，有關憲法第8條第2項規定之提審，下列敘述何者錯誤？', '["法律如以「非法逮捕拘禁」為聲請提審之條件，即與憲法第8條第2項規定有所違背", "受理提審聲請之法院，僅指負責審判之法院，不包括檢察官", "提審期間不應計入逮捕機關拘禁人民之24小時期間", "外國人非法入境而遭內政部移民署暫時收容者，因非屬刑事案件，故無憲法第8條之適用"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:19+00:00", "source_pdf_sha1": "a526a29fb5cc", "answer_pdf_sha1": "53cf396c4907", "source_family": "moex-gov-tw", "moex": {"exam_code": "111070", "c": "513", "s": "0205", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中華民國憲法與警察專業英文", "year": "111", "exam_name": "111年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "警察法制人員"}'::jsonb, NULL),
