  ('police-f3743df6-moex-00296', 'police-f3743df6', 'police-f3743df6-moex-111-15a7b19c', 'sub-police-f3743df6-01', NULL, 'single_choice', '下列何者並非憲法總綱之規定？', '["中華民國為民有民治民享之民主共和國", "中華民國之主權屬於國民全體", "中華民國領土依其固有之疆域，非經國民全體投票複決，不得變更之", "中華民國各民族一律平等"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:19+00:00", "source_pdf_sha1": "a526a29fb5cc", "answer_pdf_sha1": "53cf396c4907", "source_family": "moex-gov-tw", "moex": {"exam_code": "111070", "c": "513", "s": "0205", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中華民國憲法與警察專業英文", "year": "111", "exam_name": "111年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "警察法制人員"}'::jsonb, NULL),
