  ('police-f3743df6-moex-00298', 'police-f3743df6', 'police-f3743df6-moex-111-15a7b19c', 'sub-police-f3743df6-01', NULL, 'single_choice', '依司法院大法官解釋，有關人民納稅義務，下列敘述何者錯誤？', '["租稅與特別公課之性質並無不同", "依租稅平等原則納稅義務人應按其實質稅負能力，負擔應負之稅捐", "憲法第19條規定人民有依法律納稅之義務，依法律即是租稅法定主義", "空氣污染防治費性質上屬於特別公課"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:19+00:00", "source_pdf_sha1": "a526a29fb5cc", "answer_pdf_sha1": "53cf396c4907", "source_family": "moex-gov-tw", "moex": {"exam_code": "111070", "c": "513", "s": "0205", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中華民國憲法與警察專業英文", "year": "111", "exam_name": "111年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "警察法制人員"}'::jsonb, NULL),
  ('police-f3743df6-moex-00299', 'police-f3743df6', 'police-f3743df6-moex-111-15a7b19c', 'sub-police-f3743df6-01', NULL, 'single_choice', '土地所有權人提供私有騎樓土地供公眾通行，不得請求補償。關於其法理，下列敘述何者正確？', '["未喪失所有權而無須補償", "人民之土地負有社會義務", "缺乏相關補償之法令依據", "基於財政考量而無須補償"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:19+00:00", "source_pdf_sha1": "a526a29fb5cc", "answer_pdf_sha1": "53cf396c4907", "source_family": "moex-gov-tw", "moex": {"exam_code": "111070", "c": "513", "s": "0205", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中華民國憲法與警察專業英文", "year": "111", "exam_name": "111年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "警察法制人員"}'::jsonb, NULL)
